// In-game patch notes — the full version history, newest first. Surfaced under Stats so we can
// see the whole arc of the POC. Add a line here whenever GAME_VERSION bumps.

export interface ChangeEntry {
  v: string;
  t: string;
}

export const CHANGELOG: ChangeEntry[] = [
  { v: "v0.154", t: "The Secondary Stats page now lists the full set of 20 secondary stats — four for each of the five primaries — in a fixed order: Attack, Armor Penetration, Armor Break, Life Steal (STR); Crit Chance, Evasion, Accuracy, Combo Chance (AGI); Ability Power, Healing Power, Buff Potency, Debuff Potency (MGC); Attack Bar Gain, Initiative, Cooldown Recovery, Counter Chance (SPD); Armor, Damage Reduction, Barrier Power, Block Chance (DEF). Each is derived from its governing primary and updates live in the equip preview. (Several of these are display-only for now; their combat effects come online in later passes.)" },
  { v: "v0.153", t: "Tuned the level-up MNA roll: it's now usually +1, sometimes nothing, and a super-rare +2 jackpot (about 5%). Gentler and less swingy than the old +2/+3 spread, while still keeping a little thrill on level-up. Balance unaffected (party still finishes ~level 10)." },
  { v: "v0.152", t: "Item-card fixes: (1) +MNA is now the first thing listed under an item's white stats — right where it belongs, above the primary attributes and affixes. (2) Loot art now centers and fills its box consistently — every item sprite was re-trimmed and centered (some had built-in empty margins or sat off-center, which made them look tiny next to the well-cropped ones). (3) The Heliomancer now starts with Sunbolt at 0 MNA, so SOL staff-wielders have their signature bolt available from the very first fight." },
  { v: "v0.151", t: "MNA & leveling overhaul. (1) Gear MNA is toned WAY down — early weapons/armor now give +1–2 instead of the absurd +30s, growing gradually with rarity & item level toward late-game Archon. Weapons always carry at least +1 MNA (it still sets your class). (2) Armor can now roll MNA: an attuned piece shows its power and grants a little MNA; a piece with NO MNA now has NO attunement designation (it's neutral). (3) Leveling up is now a gamble — instead of a guaranteed +1 MNA, it's a 50/50: half the time nothing, half the time a chunky +2 (with a rare +3 jackpot), so levels feel exciting. The level-up screen now spells out your gains: +HP, +ATK, +ARM, and your MNA roll. (4) Every level reliably bumps HP, ATK, and ARM (armor now climbs for all classes, not just tanks). (5) You can now swap into ANY weapon type from the Status & Equipment screen to change class (it no longer hides other weapon types), and there's a Bag button in the top-right of that screen. Enemies were eased slightly to keep the difficulty curve fair now that ability power leans less on huge gear-MNA." },
  { v: "v0.150", t: "Item-card polish. Loot art is bigger and now sits in a framed box so it fills the card instead of floating small. The Attunement tag on every item is colour-coded to its power (SOL gold, NOX blue, ANIMA green, QUANTA red, UMBRAXIS purple), so you can read an item's element at a glance. Item stats are now clean and legible — capitalized and dot-separated with bold values (e.g. '+6 HP · +1 ARM') instead of cramped lowercase. MP has been fully removed from items everywhere (the game runs on cooldowns now). And the Victory screen's XP and Aether rewards are now bold gold-and-blue pills instead of faint grey text." },
  { v: "v0.149", t: "Stat System V3 — the five core stats are now real and on your gear. Every weapon and armor drop now carries a primary attribute (STR, AGI, MGC, SPD, DEF) on top of ATK/ARM, and those stats now DRIVE your damage: they amplify your ability output, weighted by your Mana Scaling tiers (your S stat helps most, your D stat least), so a SOL hero gets the most out of AGI gear, a NOX hero out of STR, and so on. (Tuned so early fights feel the same as before — the power comes as you find better gear.) The Party screen's 'Equipment' tab is now 'Status & Equipment' and was rebuilt: a clean stat panel with HP/ATK/ARM beside your five primaries, a toggle to a full SECONDARY-stats sheet (crit, accuracy, lifesteal, damage reduction, and more, derived from your primaries), and the Offense/Defense/Overall ratings. Equipping is now in-place: pick a slot, tap an item, and see exactly how it changes every stat — primaries, secondaries, and your ratings — BEFORE you commit. Swapping a weapon (which changes your class) now asks to confirm first. MP is no longer shown (abilities run on cooldowns now)." },
  { v: "v0.148", t: "Stat System V3 begins: the Equipment screen now shows each hero's MANA SCALING — how well their abilities scale from each of the five core stats (STR, AGI, MGC, SPD, DEF), rated S (best) → D (minimal). The tiers follow the affinity cycle: your attunement's own stat is S, the stat of the power you beat is A, and the power you're weak to is D. (This is the foundation — the new stats will start driving combat math in an upcoming pass.)" },
  { v: "v0.147", t: "Battle System 2.0 begins: abilities now run on COOLDOWNS instead of MP. Every Skill has a 2-turn cooldown — use it and it's unavailable for your next two turns, then ready again. The skill menu shows 'Ready' or 'CD 2/1', and abilities no longer cost MP. (This is a first pass — the cooldown lengths and the wider system will be tuned going forward. Ultimates remain on their own test rules for now.)" },
  { v: "v0.146", t: "Reworked the Greenvale→Silverwood journey so it finally reads as a real lock-before-key. The road EAST to Silverwood is now barred by an arm of the Sunless Gorge that reaches right into Greenvale — you can see Silverwood's shore across the chasm but cannot cross it, and (the bug is fixed) you can no longer simply walk over the gorge without the raft. The Bandit Warren is now a keyless beginner dungeon — it no longer hands you the raft. Instead the raft is recovered far to the SOUTH, in the Duskmarsh's Drowned Vault: clear that zone's boss and the raft is yours, which opens the gorge crossing east. Hearthford and Miregard townsfolk now point you along this route, and the gorge lookout reads 'Silverwood — the Sunless Gorge bars the way' until you hold the raft." },
  { v: "v0.145", t: "Healing column now fades in and out more naturally — a gentler ease-in and a softer fade-out, so it no longer pops on or cuts off." },
  { v: "v0.144", t: "Healing effect: removed the rotating circle at the target's feet for now — the heal is just the vertical column of rising energy." },
  { v: "v0.143", t: "Tuned the healing effect so it actually reads: the ground rune is larger and clearly sits under the recipient, and the rising energy column now towers over them and is bright enough to see against the battlefield (it was washing out and looked tiny)." },
  { v: "v0.142", t: "Healing now has its own effect. When a hero heals, a soft healing circle blooms beneath the recipient — a slowly-spinning ground rune with a gentle column of themed energy rising around them, in the CASTER'S Attunement color (SOL golden sunfire, NOX blue frost, ANIMA green life with leaves, QUANTA red geometry, UMBRAXIS purple void). It's kept semi-transparent so the character stays fully visible, fades in, pulses calmly, and the heal lands as it finishes — then it fades away. Used for every healing ability." },
  { v: "v0.141", t: "Casting circle polish: it now sits flatter on the ground (less like a round coin, more like a rune laid on the floor), and it fades out smoothly at the end of the cast instead of snapping off." },
  { v: "v0.140", t: "Fixed the casting circle's rotation. It was tumbling like a coin on its edge; now it spins flat in the ground plane — a disc turning under the hero's feet, exactly as a magic circle should. (The runes rotate within a fixed ground ellipse.)" },
  { v: "v0.139", t: "Abilities now have a casting tell: when a hero uses any ability, a glowing mana CIRCLE in their Attunement's color (SOL gold, NOX blue, ANIMA green, QUANTA red, UMBRAXIS purple) appears on the ground under their feet. It fades in, slowly spins and pulses for about 1.5 seconds while the hero focuses, and the ability's effect lands as the cast completes — then the circle fades away. It scales to the caster, stays put, and sits beneath the hero so they stand atop it. Applies to every ability, even ones without a unique animation." },
  { v: "v0.138", t: "All-new combat hit effects. Every damaging hit — normal attacks, skills, signatures, ultimates, on heroes and enemies alike — now flashes a sharp mana-colored SLASH right over the target, in the attacker's Attunement (SOL gold, NOX blue, ANIMA green, QUANTA red, UMBRAXIS purple). It snaps in, glows at peak with a little burst of particles, and fades out in a fast ~1/6 second — no more sliding bursts, just a crisp, responsive impact like the slashes in modern JRPGs. Combo hits stay lively: each strike randomizes the slash's angle, size, and position slightly. Critical hits hit harder visually — bigger, brighter, more particles, and a subtle screen shake. The slash mirrors direction depending on who's attacking (heroes' slashes sweep the opposite way from enemies'). This replaces the old impact-burst and crit-spark effects entirely." },
  { v: "v0.137", t: "Swapped the low-res mountains battle backdrop for a crisp, high-resolution painting of the same alpine valley — a sweeping meadow under snow-capped peaks, with no baked-in characters. Sharper and cleaner behind every mountain-environment fight." },
  { v: "v0.136", t: "The Lagrangian (Umbraxis · Dual Daggers) joins the ultimate roster with UMBRAXIAN FEALTY — and gets his real idle sprite: a hooded reaver wreathed in void with twin glowing daggers, his look going forward. Unlike the Vanguard's Orbital Cannon, this ultimate is SINGLE-target: choose one foe, the screen fades to its full-resolution cutscene, then fades back and that one enemy is unmade for 9999. Like the Vanguard's, it's a test build — free and usable every turn while we tune it." },
  { v: "v0.135", t: "First look at ULTIMATE abilities. The Photon Vanguard now has a new 'Ultimate' button in battle (lower-left, between Skill and Defend); open it to unleash his ORBITAL CANNON. When you do, the screen fades to black and plays a full-resolution cutscene — then fades back to the fight, where the strike lands on EVERY enemy for 9999. This is a test build: it's free and usable every turn so we can iterate on the feel. Numbers, cost, and cooldown are all placeholders for now." },
  { v: "v0.134", t: "A few visual fixes. The Photon Vanguard now stands a bit larger so he matches the other heroes' size in the party row. And two Attunement text colours are corrected: QUANTA reads RED (was purple) and UMBRAXIS reads PURPLE (was a washed-out grey) — across character names, item tags, and the title screen — so the colours line up with their impact effects." },
  { v: "v0.133", t: "Fixed the combat impact bursts sliding sideways across the enemy. The four frames were painted at slightly different spots on their sheets, so as the animation played the bright mass drifted across the sprite — it read as a slash sweeping past rather than an impact landing. Each frame is now re-centred on its own bright core, so all four are concentric: the burst blooms in place, locked dead-centre over the struck enemy, with no movement on either axis. Also snappier now (~0.33s) so it reads as a single decisive hit." },
  { v: "v0.132", t: "Smoothed out the new combat impact bursts. They now play as one continuous dissolve — frame 1 melts into 2 into 3 into 4 in a single smooth blend right on top of the enemy, instead of snapping between frames — and the whole burst is held a touch translucent so the foe still reads through it. Centred squarely over the struck sprite." },
  { v: "v0.131", t: "Combat hits now land with a real impact — every successful attack detonates a burst of energy right on the enemy, coloured by the attacker's Attunement: a golden flare for SOL, ice-blue for NOX, green for ANIMA, red for QUANTA, and violet for UMBRAXIS. The effect is Dara's five hand-painted four-frame explosions (slash → full burst with a ring → flying shards → dissipating sparks), played centred on the struck foe and sized to it. It fires for everything — basic attacks, abilities, multi-hit and area attacks, and crits (which still add their own spark on top) — so combat reads with a satisfying punch on every blow. Abilities with their own bespoke hit effect (like the Photon Vanguard's solar burst) keep theirs; everything else now gets the matching Attunement impact." },
  { v: "v0.130", t: "Fixed the Photon Vanguard's intermittent vanish during combat animations — for real this time. The root cause: the animation waited for every frame image to finish preloading before it would start, but on iOS / the installed web app a cached image's 'loaded' signal can simply never arrive, so the whole sequence stalled — the hero was hidden and nothing drew for about a second, then he popped back at the end. The animation no longer waits on preloading at all: it starts immediately, each frame draws right away and sharpens to its exact proportions the instant it loads, and the hero is hidden and restored purely on the animation's own clock. So the firing frames, muzzle flash, bullet and impact always play on time and he never disappears." },
  { v: "v0.129", t: "The Photon Vanguard's basic attack is now a real gun shot. Targeting a foe with a plain Attack plays the full sequence: he runs his firing poses, a SOL muzzle flash blooms at the rifle barrel, a gold tracer bullet streaks across to the enemy, and a solar burst detonates on impact — damage lands as the bullet hits and the number floats up after the blast. Built on the same animation pipeline as the Photon Beam, now extended with two reusable phases — a muzzle/cast flash and a travelling projectile — so any future gun or projectile class can fire the same way. (Dara's three new VFX sheets — muzzle flash, bullet, impact — are catalogued for reuse.)" },
  { v: "v0.128", t: "The Photon Vanguard gets his real idle sprite — a crisp, hand-cut transparent pose of him braced and aiming, no more washed-out edges. And the intermittent flicker is fixed: when the skill played, the hero's sprite was briefly given a 'lunge' bob a frame before the animation hid it, so depending on timing you'd sometimes see him twitch-then-vanish. Animated abilities now skip that lunge and hide the static sprite instantly, so the Vanguard reads cleanly every cast." },
  { v: "v0.127", t: "The Photon Vanguard no longer vanishes mid-shot. His firing frames ended partway through, but his static sprite stayed hidden until the whole animation finished — so he was absent for the entire beam + explosion (and the beam looked like it came from empty space). Now the hero is hidden ONLY while his firing frames play, then his sprite returns in its final firing stance and HOLDS that pose through the beam and impact — so he's on screen the whole time and the beam clearly fires from his gun." },
  { v: "v0.126", t: "Photon Beam is a clean, connected beam now. Before, the beam art tapered to faint points at both ends, so stretched across the gap it looked broken and never reached the gun. The beam is now rebuilt into a UNIFORM bar (from the bright core of Dara's art, keeping its gold look) and the engine ROTATES it to connect the Vanguard's muzzle exactly to the enemy — so it reads as one smooth, continuous beam that collides cleanly into the Sol-Aloha explosion on the target. Muzzle alignment tightened too." },
  { v: "v0.125", t: "Fixed the Bandit Warren entrance. After the Warren's mouth was relocated (so you now meet the Sunless Gorge BEFORE the dungeon), climbing back out of the Warren dropped you a few tiles away from the entrance instead of right on it — the exit was returning you to the mouth's OLD, pre-move spot. Now you always step back out exactly onto the Warren mouth you went in through. (Root cause: the overworld remembered a stale default mouth position when a run started in Greenvale and never refreshed it to the relocated one; locked with a regression test.)" },
  { v: "v0.124", t: "Photon Beam reliability fixes. The Vanguard was flickering / vanishing mid-animation and the beam was usually invisible — two real bugs. (1) Each frame swapped a single image's source, which makes the browser re-decode and flash blank every frame; now all of a layer's frames are pre-loaded and stacked, and we just cross-fade which one is visible (no source swapping). (2) The beam and explosion used a 'screen' blend that washes bright effects out to nothing over bright backgrounds (grass, sky); they now render normally with a gold glow, so the shot and the hit on the enemy are always visible. Also nudged the muzzle origin. (Still dialing in exact muzzle/beam alignment.)" },
  { v: "v0.123", t: "Greenvale's ground is real painted art now. The grass, the tended orchard sward, the dappled forest floor, and the dirt roads and root-trails that were flat placeholder colour (and read as a muddy dark grid) are replaced with Dara's hand-painted tiles — lit, warm and clearly walkable — so the open world finally looks like sunlit shire and old-growth wood instead of a dark checkerboard. (First art drop of the overworld refresh: the walkable GROUND across Greenvale and Silverwood; the trees, bushes and rocks get their own painted props in the next pass.)" },
  { v: "v0.122", t: "Photon Beam now reads as a real ranged shot. The Photon Vanguard stays put and animates through his five poses IN PLACE (a sniper doesn't run at the enemy), then on the firing beat a photon beam springs from his gun muzzle and spans to the foe, and the Sol-Aloha explosion blooms on the enemy as it lands — damage on impact, number after the blast. The sprites are also crisper: the background knockout now flood-fills only from the edges, so the Vanguard's bright gold highlights stay solid instead of going semi-transparent (that was the 'faded' look). His idle stance got the same clean treatment." },
  { v: "v0.121", t: "The overworld is far easier to read. The open world had become a muddy dark checkerboard where it wasn't clear what you could walk on — the very ground under your feet could look like a wall. Now terrain reads at a glance: walkable ground is lit, warm and flat; trees, rocks and cliffs stand UP off the floor and cast shadows so they obviously block the way; and water and chasms sit in a cool, sunken channel with a lit bank so they clearly read as 'you can't cross here.' The dreary darkening that washed out the forest floor is gone, Greenvale's grass and groves look brighter and more alive, and the whole world now has a consistent sense of depth and light. (Tuned first on Greenvale; the same depth treatment already lifts every region, with each biome's own colours to follow.)" },
  { v: "v0.120", t: "Smoother Photon Beam — the firing figure no longer 'clips' across the screen. Each animation layer used to stamp its frames as separate fading images at stepped positions, so the advancing Vanguard read as a row of overlapping ghosts marching toward the foe. Now each layer is a single sprite that swaps its frames in place and GLIDES smoothly toward the enemy, fading in and out as one — so the advance-and-fire reads as one clean motion." },
  { v: "v0.119", t: "Photon Beam now actually shows — and the Photon Vanguard gets his real pose. The animation frames were being drawn before the images had loaded, so they had zero size and the quick fade finished before anything painted (nothing visible). The compositor now PRELOADS every frame and gives each one an explicit width and height, so the character, beam, and explosion render cleanly the moment you fire. And the Photon Vanguard's idle battle sprite is now his FINAL STANCE pose from the art sheet — he stands ready, rifle in hand, between actions." },
  { v: "v0.118", t: "First step toward fully animated combat — a layered animation pipeline, debuting on the Photon Vanguard (SOL × Rifle). Build one in the Roster picker and its single test ability, PHOTON BEAM, now plays a real sequence when you target a foe: the Vanguard advances and fires (5-frame character animation), a photon beam springs from the muzzle, and a Sol-Aloha explosion blooms on the enemy as the shot lands — damage applies mid-fire and the number floats up after the blast, every frame fading in and out like the crit bursts. Under the hood it's a reusable compositor that layers character + effect + impact frames over the live battlefield (backgrounds are never baked in) from a JSON skill definition (frame count, timing, anchor, offset, scale, flip, which frame deals damage). This is the foundation we'll build the rest of the combat animations on." },
  { v: "v0.117", t: "Finding your way to Silverwood is no longer a guessing game. The road out of Greenvale now LEADS you: Elder Maelis in Hearthford points you east — to the ancient wood of Silverwood, beyond the Sunless Gorge — and warns that the bandits of the Warren hold the only way across. Push east and you'll hit the gorge itself: a sheer, impassable chasm with the great Elder-Oak of Silverwood looming on the far rim (you can SEE where you're headed before you can reach it). So when you break the Bandit Kingpin and haul out his raft, you already know exactly what it's for. The chasm now TRULY seals the way (no more accidentally wandering around it), and the first time you raft across, a one-time note marks the crossing so you know you did it. Plus a new zoomed-out MAP: open the map and tap 'Continent' for a view of all the Aurelion you've discovered — your position and where to head next lit up, with new places revealed as you hear of them. You should always know where to go now." },
  { v: "v0.116", t: "Two battle-screen fixes. The ability list (bottom-left during a turn) no longer overlaps itself — when a skill's description ran long, the button was being squeezed shorter than its text and the words spilled over the next ability's border. Buttons now keep their full height and the list scrolls instead, so every ability and its description read cleanly. And the Bandit Kingpin's enraged OMEGA form was still facing left, away from the party — mirrored so he faces right toward the heroes like the rest of the battle line." },
  { v: "v0.115", t: "Silverwood's monsters now face the right way. The whole Ancient-Forest roster — the Direwolf, Thornling, Sylvan Archer, Gloom Wisp, Barkhide Brute, Spriggan, and the Hollow King himself — had been drawn facing LEFT, away from your party, instead of squaring up toward the battle line like every other foe. Flipped all seven to face right (the Elder Treant was already fixed). No more fighting monsters who've turned their backs on you." },
  { v: "v0.114", t: "Fixed a battle that could strand you after beating a zone boss. Two bugs stacked up on the Bandit Kingpin fight: (1) if a hero began a turn with a lingering status (burn, etc.) right as another hero landed the killing blow, the game could paint a stale command menu onto the already-won fight; and (2) climbing out of the dungeon after a boss win rebuilt the overworld but never actually switched the screen away from the battle — so dismissing the loot screen dropped you back onto a dead battle screen with no way forward. Now the victory tears down any leftover menu, and the climb-out properly returns you to the overworld (raft in hand) to strike out for the Sunless Gorge. Locked both with regression tests." },
  { v: "v0.113", t: "Town labels no longer hide behind the scenery. Building signs (Inn, Market, Smith, Shrine…) and townsfolk names are now drawn in a single pass ON TOP of everything, so the row of tiles just below a building — or a taller neighbour standing in front — can't paint over the caption anymore. Labels near the edges of the screen are also nudged inward so they're no longer clipped (no more half-cut 'Goodwi…'). Under the hood we also added a guard that proves every cave and dungeon entrance is reachable AND enterable — so you should never stand on a dungeon mouth that won't let you in." },
  { v: "v0.112", t: "Every dungeon is its own place now. Until this patch, seven of the ten dungeons were the SAME two maps copy-pasted with different names — clear the Sea-Cave and you'd already 'seen' the Stronghold, the Crypt, the Citadel. All seven have been rebuilt from scratch into distinct layouts that read like what they are: the WINDMILL UNDERCROFT descends a granary cellar around a threshing pit; the DWARVEN STRONGHOLD is a forged, blocky grid of square halls around a great forge; the BESIEGED CITADEL climbs concentric defensive wards to a lighthouse summit; the BREACHED UNDERVAULT is a cracked-open strong-room ringing a collapsed rotunda; the RELIQUARY CRYPT is a solemn nave with burial chapels off it; the SMUGGLER'S SEA-CAVE is a wave-cut tangle of tidal caverns; and the SMUGGLERS' DEN is a cramped bolt-hole of hidden little rooms. Each true dungeon also gets its own tailored rest reprieve (a forge-vent, a lighthouse lamp, a reliquary altar…) while the two caves stay restless and punishing end-to-end. No two dungeons feel the same anymore." },
  { v: "v0.111", t: "Dungeon rest stops are no longer a free full heal. A campfire inside a dungeon used to restore ALL your HP and MP — every floor — which quietly trivialized the climb. Now a rest node gives a TAILORED reprieve: it relieves one thing, partially, themed to that dungeon, and leaves you to press on imperfect. The Bandit Warren's hearths now bind WOUNDS only (about 40% HP, no magic) — so the three-floor descent never refills you, and spent spells stay spent until a town. (Under the hood this adds three reprieve flavors — mend/HP, mana/MP, and a carried regeneration that only heals once you're back in a fight — so future dungeons can each rest differently. CAVES get no rest at all, staying punishing end-to-end.) Groundwork for giving every dungeon its own distinct feel." },
  { v: "v0.110", t: "Your party menu's Items tab is no longer a 'coming soon' placeholder — it's a real inventory. It holds two kinds of things: QUEST ITEMS, which you keep for the whole run and never use up (keys, sigils, and the like), and CONSUMABLES (potions, antidotes…) for later. The first quest item is already in play: beat the Bandit Kingpin and you'll be handed the LASHED RAFT, hauled out of the Warren — and CARRYING the raft is what lets your party cross the Sunless Gorge into the Silverwood. So the road south now opens because you're holding the thing that crosses it, not by invisible bookkeeping. Your held items are saved with your run (and an in-progress save that already earned the crossing finds the raft waiting in its Items tab)." },
  { v: "v0.109", t: "Two fixes. A real battle hang is gone: when the LAST enemy died to a damage-over-time tick (poison/burn/decay/drain) at the start of its own turn, the fight never noticed it was over and just sat there — now a DoT kill correctly resolves the battle (victory or, if it's your last hero, defeat). And the Elder Treant (Silverwood's mini-boss) was facing away from the party — flipped to face the heroes." },
  { v: "v0.108", t: "Bandit Bloodknife and the Bandit Kingpin (and his enraged Omega form) were facing the wrong way — away from the party. Flipped them to face right, toward the heroes, like the rest of the battle line." },
  { v: "v0.107", t: "The towns are peopled. All 42 townsfolk across the seven Aurelion front doors now show hand-painted character sprites instead of emoji — the forest-folk of Elderbough, the farmers of Wheatcross, the fisherfolk of Wrackport, the dwarves of Frosthold, the soldiers of Lastlight, the monks and nuns of Vesperhal, and the port folk of Sunpier, each greeting you in their own dress. And the Rimespine Mauler gets its painted sprite, so Frostpeak's new frost-beast prowls the passes in the flesh. With this, the whole Aurelion art pack is in: every town, dungeon, biome, foe, and face is real art." },
  { v: "v0.106", t: "The later regions' foes stop being emoji. All five rosters now fight with real hand-painted sprites — the Storm Coast wreckers (Coast Wrecker, Tide Cutthroat, Pirate Slinger, Reef Crab, Brine Serpent), the Frostpeak frost-beasts (Ice Wolf, Mountain Reaver, Frost Shade, Dwarven Sentinel, Snow Troll, the Glacier Guardian + its enraged form), the Dawnfall fallen watch (Frontier Stalker, Broken Sentry, Garrison Ghoul, Rampart Hulk, Fallen Sentry), the Whisper Hills cloister-horrors (Restless Wraith, Corrupted Monk, Cloister Flagellant, Reliquary Golem, Crypt Revenant), and the Sunbridge siege & the deep (Siege Trooper, Sea-Raider, Ballista Crew, Abyssal Spawn, Drowned Sailor, Siege Ram, and the Risen Leviathan + its enraged form)." },
  { v: "v0.105", t: "The later overworld stops looking like Greenvale with the colours changed. Three biomes now roam over their own hand-painted terrain instead of flat fills: the FROSTPEAK snowfields (packed snow, glacier ice, frozen pools, snow-laden pines and cairns), the STORM COAST / SUNBRIDGE shore (wet sand, surf, teal sea, weathered docks, coastal rocks and pilings), and the DAWNFALL ruins (cracked flagstone, rampart walks, crumbling walls, rubble and dry moat-pits). Each biome's ground, paths, water and scatter now read at a glance." },
  { v: "v0.104", t: "Aurelion gets its real look. The seven front-door towns now render their own hand-painted tilesets instead of all borrowing Hearthford's village — Elderbough's mossy forest lodges, Wheatcross's burning wheat-stacks, Wrackport's grey wreckers' harbour, Frosthold's rune-cut dwarven stone, Lastlight's grim timber palisade and watch-bonfire, Vesperhal's pale cloister and bell-tower, and Sunpier's bright sea-wall, pier and lighthouse. And the six later dungeons get bespoke tilesets too: the Smuggler's Sea-Cave, the Dwarven Stronghold, the Breached Undervault, the Reliquary Crypt, the Besieged Citadel, and the Smugglers' Den — each with its own floors, walls, chest, entrance and lit decoration, instead of reusing the Warren/Grove/Vault skins." },
  { v: "v0.103", t: "Six more regions get their own front-door towns — every Aurelion zone now arrives at a real, walkable place named by Dara, instead of borrowing a placeholder hub. WHEATCROSS, the breadbasket's burning farm-crossroads before Goldmeadow (the Reaping Warlord's host has taken the mill); WRACKPORT, a storm-coast wreckers' harbor; FROSTHOLD, a dwarven hold-gate carved into the Frostpeak snow (its deep Sentinels turned against their makers); LASTLIGHT, the last frontier garrison before Dawnfall, where the watch has fallen and you'll fight your own dead; VESPERHAL, a hillside cloister whose order has been corrupted from within; and SUNPIER, the great archipelago port making its last stand against the siege — and the Risen Leviathan. Each has its own inn, market, smith and shrine, and five-to-six NPCs whose talk tells you what waits on the road ahead. (Layouts verified soft-lock-free; on-brand voices grounded in each region's canon roster.)" },
  { v: "v0.102", t: "Silverwood gets its own front door: ELDERBOUGH, a walkable forest hamlet. Until now, arriving in the Ancient Forest dropped you back through the grand capital Riverhearth; now the journey into Silverwood passes through Riverhearth and then ENDS at Elderbough — a green-hush village of lodges grown up among the great trees, with its own inn, market, smith and grove-shrine, and woodfolk who speak soft because the wood has WOKEN. Talk to the forest-warden, the grove-keeper, the woodcutter who won't raise his axe to the wood anymore — they'll tell you what waits on the south paths (the Elder Treant stirring, the Hollow King in the Sunless Grove) before you set out. (First of the seven new regional towns Dara named.)" },
  { v: "v0.102", t: "The attack flicker is actually fixed this time. v0.97 toggled the lunge/hit animation in place, but every attack immediately re-painted the whole battle screen afterward — and that re-paint wiped and rebuilt every combatant's sprite from scratch, flashing a blank frame at the start AND end of each swing (heroes and enemies both). The battle screen now RECONCILES in place: it keeps each sprite element alive across re-paints and only refreshes the bars, numbers and status badges, rebuilding a sprite solely when its art genuinely changes (a hero falling to 💤, or a boss enraging into its Omega form). So lunges and hits now animate perfectly cleanly — no more flicker." },
  { v: "v0.101", t: "Loot rarity, dramatically re-curved — and the drop tables moved into data so they're easy to tune. High-rarity gear was showing up far too early: Greenvale's chests handed out guaranteed rares (with the odd artifact!), and the zone boss dropped epic-or-better. Now the whole curve is STEEP and level-gated — early on (≈L1–10, the playable arc) you'll see mostly commons and uncommons, a RARE is a genuine treat, and epics/legendaries/artifacts are a deep-level reward that simply doesn't appear in the starting zones. Chests, the merchant, and combat drops all run off the same level-banded table now (in `data/loot.ts`: the bands, the lucky-spike rate, and the per-source bumps for elites/bosses/treasure-monsters), so tuning the economy is a one-file edit." },
  { v: "v0.100", t: "Dungeons get atmosphere. Room-facing walls now occasionally bear a lit decoration — guttering TORCHES in the Bandit Warren, hanging LANTERNS in the Drowned Vault, and clusters of glowing SPORES in the Sunless Grove — so the corridors feel lived-in and lit rather than uniformly dark. (Placed deterministically and sparingly along walls that face into a room.)" },
  { v: "v0.99", t: "The Bandit Warren's last two placeholders get real art. The BANDIT HEARTH (the breather node that heals your standing heroes once per floor) is now a painted campfire — a cook-pot on a spit over a stone fire-ring, bedroll and axe beside it — instead of a 🔥 emoji. And the COLLAPSE DROP (the one-way shortcut that caves you down a level) is now a painted pit of broken timbers and rubble around a black hole, instead of a 🕳️ emoji. With this, every tile in the playable dungeons is on real, hand-painted art." },
  { v: "v0.98", t: "The three dungeons get fresh, fuller tilesets. The Bandit Warren (timber & dug earth), the Sunless Grove (living roots & wood — Silverwood), and the Drowned Vault (mossy stone — the Duskmarsh) all have repainted floors, paths, walls, rubble, chests and tunnel mouths, so each dungeon reads as its own distinct place rather than a generic cave. (Three of Dara's tileset sheets, knocked off the magenta and sliced in; some new wall-decoration tiles — torches, lanterns, glowing spores — are prepared for a later atmosphere pass.)" },
  { v: "v0.97", t: "Gear-art + battle polish. Spellblade weapons (e.g. the Thornclad Runeblade) are no longer cut off at the bottom — the slicer was cropping the blade too tightly to dodge a baked-in name caption; it now keeps the whole blade and drops just the caption. Item icons are bigger and squarer so the art fills the box properly — chest armour pieces (Solar Cuirass, Void-Touched Cuirass, Probable Plate) no longer sit tiny in a wide frame. And the brief sprite FLICKER at the start and end of every attack is gone: combatant sprites are no longer torn down and rebuilt each time a lunge or hit plays (the animation classes toggle in place, and sprites decode synchronously), so attacks animate cleanly for heroes and enemies alike." },
  { v: "v0.96", t: "Fixed zone progression after a dungeon boss. Beating the Bandit Warren wrongly whisked you off to the far 'main city' (a placeholder hub for a later region), and then choosing to set out for Silverwood dumped you right back in Greenvale. Now clearing a zone's boss returns you to that zone's OWN hub town (Hearthford, with the merchant) for a breather and restock, and setting out from there takes you to the correct next region. (Two bugs: the post-boss step pointed at the next zone's placeholder doorstep instead of your current hub, and the seamless-world zone-advance always re-dropped you at Greenvale's spawn.)" },
  { v: "v0.95", t: "The Bandit Warren is redesigned — and the dungeon chests look right. Instead of three identical rings of corridors, the Warren now has three distinct floors with a real explore→fight→rest→descend rhythm: the TUNNEL WARREN (a branching burrow with a hidden collapse-drop shortcut), the BARRACKS & VAULT (the bandit lieutenant gates BOTH the stairs down and a locked treasure vault — beat him to claim it), and the KINGPIN'S THRONE HALL (looping galleries that rejoin at a last campfire before the Kingpin, who's now in full view the moment you step in). New touches throughout: a BANDIT HEARTH on each floor that fully heals your standing heroes once (a breather before the danger spikes), and one-way COLLAPSE DROPS that cave you down to a shortcut. Plus the dungeon treasure chests now show their real painted art with a soft glint, instead of a placeholder 💰 'loot' tag slapped on top." },
  { v: "v0.94", t: "Fixed the new helm/glove/boot art — several pieces showed a sliver of the next item overlapping their icon. The slicer was cutting each rarity strip into six equal columns, but the painted items don't sit on an exact grid, so wider/higher-rarity pieces drifted into their neighbour's slice. It now finds the real empty gaps between the items and cuts there, so every helmet, gauntlet and boot is captured whole and clean — no more overlap or clipping (boots, which come as a pair, stay together correctly)." },
  { v: "v0.93", t: "Fixed: after beating the gate guardian, the mouth of the Bandit Warren (and every zone's dungeon mouth) wouldn't let you descend — stepping onto it did nothing. The overworld map is streamed in chunks, and the code that opens the gate after the mini-boss only updated the old map representation, so the streamed gate stayed shut. It now opens the mouth in the live world and you can walk straight in." },
  { v: "v0.92", t: "Helms, gloves and boots get their own art. Until now those three slots all borrowed the chest piece's look — now every one has its own hand-painted sprite, themed to its Attunement and escalating with rarity: radiant SOL gold, frostbound NOX ice, verdant ANIMA growth, cosmic QUANTA violet, and dread UMBRAXIS black-and-red — each climbing from a plain Common to a blazing Artifact. That's 90 new pieces (3 slots × 5 powers × 6 rarities) showing through everywhere gear appears: loot drops, the Bag, the merchant, and the Equipment screen. (Dara's art, knocked off the magenta and sliced via the new equipment pipeline.)" },
  { v: "v0.91", t: "The installed app now AUTO-UPDATES. Before, a pinned Home-Screen copy could stay stuck on an old build until you deleted and re-added it (iOS keeps web apps suspended and serves the cached copy). Now the app checks for a new version every time you open or return to it, and quietly reloads to the latest build — your run is saved and restored, so you don't lose your place. Under the hood the service worker is version-stamped each release so updates are reliably detected. (One-time note: relaunch the pinned app once to land on this version, and it'll keep itself current from here on.)" },
  { v: "v0.90", t: "Full-screen play + a real iOS bottom tab bar. On a phone (and the installed app) the game now fills the WHOLE screen instead of sitting in a letterboxed box with dead black bars — the world map uses every pixel. The overworld controls are now a proper iOS-standard TAB BAR: a full-width bar pinned to the very bottom of the screen, running edge-to-edge through the home-indicator area, with evenly-spaced Party / Bag / Map / More items and a clean divider above it (just like the Files app). The desktop browser keeps the framed 920×640 view, and a browser tab still gets the floating d-pad above the bar." },
  { v: "v0.89", t: "A cleaner, app-native interface. The overworld controls are consolidated into a tidy BOTTOM DECK that rides the iPhone's home-indicator safe area: your Party, Bag, Map and a 'More' button sit in one row, and More slides up a sheet for Stats, Egress, music and mute — clearing the old clutter off the top of the screen (now just location, Aether and party). In the INSTALLED app the movement d-pad is hidden and you simply TAP or PRESS-AND-HOLD toward where you want to go (a browser tab keeps the d-pad). Plus the app now KEEPS THE SCREEN AWAKE while you play, opens on a branded gold-sun SPLASH instead of a blank flash, adapts its chrome to whether it's installed or in a tab, and (in Safari) offers a one-time tip to add it to your Home Screen." },
  { v: "v0.88", t: "Gaia now works OFFLINE and loads instantly. A service worker caches the game on first visit, so the installed app opens with no connection (on a plane, underground, dead zone) and subsequent launches are near-instant from cache instead of re-downloading. When you're online it still picks up the latest version automatically. Pure static caching — no accounts, no servers." },
  { v: "v0.87", t: "iOS app polish, from an iOS-PWA review. The overworld map is now CRISP on retina iPhones/iPads — the field canvas renders at the device's true pixel density instead of upscaling a low-res buffer (it was soft/chunky before). Music now RESUMES when you return to the app after switching away (iOS silences a backgrounded web app's audio), and your run is SAVED the moment the app is hidden, so iOS quietly reclaiming it can't lose your spot. Plus: the on-screen battle commands and menu buttons are now full finger-height (44pt) touch targets, the game honors the system 'Reduce Motion' setting (the title sun and rare-monster shimmer stop pulsing), and the Home-Screen icon gets a maskable variant so it sits cleanly in adaptive icon masks." },
  { v: "v0.86", t: "The last two emoji tiles get real art — the placeholder sweep is done. Hearthford's VAULT is now a painted stone strongroom (iron-banded door, lantern glow, shield crest) in place of the 🏦 icon. And the dungeon BOSS no longer sits on a crown emoji — the finale tile is a hand-painted THRONE OF THE LAIR: a jagged black-and-gold seat on a dais, blood banners, lit braziers, skulls and scattered gold (it dims to a planted flag once you've cleared the boss). The 'BOSS' beacon + glow stay so it's still unmissable. With this, every tile, building, prop, enemy, townsperson and the player are on real, hand-made art." },
  { v: "v0.85", t: "Gaia installs like an app on iPhone & iPad. Add it to your Home Screen and it launches FULL-SCREEN with no Safari address bar — its own gold-sun icon and dark title chrome. The playfield now respects the notch, Dynamic Island and the home-indicator bar (so the HUD and the on-screen d-pad never hide behind them, in portrait or landscape), and the page no longer rubber-band-scrolls, zooms, or pops a text-selection menu on a long press. It feels like a native game, not a web page. (Also installable as a standalone app on Android/desktop Chrome via the web manifest.)" },
  { v: "v0.84", t: "The gate guardian gets a face. The mini-boss that blocks a dungeon's mouth (and the lieutenant gating each dungeon floor) no longer shows a placeholder helmet icon — it now stands on the gate as its ACTUAL painted monster: the Bandit Brigadier mustering at the Warren mouth, the Vault Broodmother webbed across the marsh descent, and so on. Reuses the battle art, so the thing barring your way is the thing you're about to fight. (Part of the ongoing sweep replacing the last emoji placeholders with real art.)" },
  { v: "v0.83", t: "The hero walks. The player is no longer a single static sprite that slides across the world — it's a full hand-painted WALK CYCLE. Your adventurer now faces the way you're heading (down / up / left / right) and strides as you move, legs and cloak in motion, settling on a neutral stance when you stop. Works everywhere you roam — the open world and inside the towns." },
  { v: "v0.82", t: "The last emoji leaves town. The walls ringing the settlements were still drawn as a row of green pine-tree emoji — old art that clashed with the now-painted towns (most glaring in grim, drowned Miregard, where bright cartoon pines fenced a fog-bound bog). The perimeter is now a real PALISADE: Miregard is ringed in painted dead-timber stakes (matching its drowned-tree decorations and the lore — 'a palisade of dead timber rings it'), Hearthford in a painted hedgerow/treeline, and Riverhearth in a layered stone curtain wall. Every town now reads as one hand-painted piece, edge to edge." },
  { v: "v0.81", t: "The last placeholders fall — and you get a face. The Windmill Undercroft beneath Goldmeadow now has its OWN granary tileset (grain-dusted timber floors, stacked grain-sack walls, spilled-grain rubble, a windmill cellar door) instead of borrowing the stone Vault's look. And the hero you steer across the world is now a painted young adventurer — green cloak, sword at the hip — in place of the old placeholder walker. With this, every tile, dungeon, town, townsperson, enemy and the player are all on real, hand-made art." },
  { v: "v0.80", t: "Towns and townsfolk get painted. The two remaining settlements have real tilesets now: MIREGARD, the grim marsh stockade (plank boardwalks over black bog, stilt-houses, drowned trees, lanterns in the fog), and RIVERHEARTH, the lamplit trade city (paved avenues, a bright river crossed by an arched stone bridge, docks, grand halls, townhouses, market stalls, a civic statue). And every TOWNSPERSON is now a hand-painted figure instead of an emoji — Hearthford's elder, watchman, child, farmer and innkeeper; Miregard's marsh-warden, bog-healer, stranded trader and bog-fisher; and all of Riverhearth's crier, dockhand, guildmaster, guard captain, ferryman, noble, busker and fishwife. Plus Greenvale's orchard and golden-wheat ground variants. The whole built world — every zone, dungeon, town and face — is on real art now." },
  { v: "v0.79", t: "One consistent painted world. The older, lower-res starter art is refreshed to match the new style: Greenvale's shire (grass, paths, trees, bushes, rocks), the Bandit Warren cave (dirt floors, timber-braced walls, rubble, the cave mouth), and the Drowned Vault (wet flagstone, flooded corridors, barnacled chests, the vault gate) are all repainted — and the Sunless Grove dungeon, which had no art at all (flat colour), now has its own hollow-heartwood tileset (living-wood floors and walls, root passages, fungus, a hollow-trunk doorway). Greenvale and all three dungeons now read as one cohesive, hand-painted world." },
  { v: "v0.78", t: "The world gets its first real ART. Painterly hand-made art replaces the flat-colour and emoji placeholders across big swathes of the game: the MARSH (boggy ground, a plank boardwalk, black water, drowned trees, reeds), the FOREST (mossy floor, root trails, ancient trees, ferns, mushrooms, orchard & wheat), and shared TERRAIN — cliffs, rivers, bridges, fords — plus map features: roadside shrines, encampments, standing stones, signposts, treasure chests and dungeon stairs. Hearthford is now a proper painted village (cobbles, inn, market, smithy, shrine, fountain, well, cottages). And whole enemy rosters get faces at last: the Silverwood forest foes (direwolf, thornling, sylvan archer, gloom-wisp, barkhide brute, spriggan, the Elder Treant, the antlered Hollow King, the mossback), the Bandit Bloodknife, and the Goldmeadow war-host (raiders, marauders, harriers, dogs, carrion birds, iron reavers, the war-captain, and the Reaping Warlord with a fearsome enraged form). (More art still to come — towns of Miregard & Riverhearth, NPC portraits, and the remaining tilesets.)" },
  { v: "v0.77", t: "You can finally SEE where you can walk. The marsh (and forest) were unreadable: with the terrain art still placeholder, the walkable path, the open ground, and the impassable tree-walls all rendered as the SAME dark colour — and the one tile that stood out was actually a wall — so the way through vanished into the bog and the bright tiles blocked you. Fixed the colours so walkable reads LIGHT and walls read DARK: the causeway is now a bright tan boardwalk (the obvious road), open ground a mid green, and the tree-walls / standing water / reed-hummocks all go dark and recede. Follow the bright tiles, avoid the dark ones — finding the Drowned Vault (and any path) now reads at a glance. (Real marsh/forest art still to come; this fixes the placeholder legibility.)" },
  { v: "v0.76", t: "Finding the dungeon is no longer a puzzle. Two fixes after the Drowned Vault proved impossible to find: (1) every dungeon ENTRANCE now glows — a gold halo + ring on the tile with a labelled pill you can read from across the map ('▶ The Drowned Vault', or '⚔ …' when a mini-boss still guards the way in), so you can spot the way down at a glance. (2) The Duskmarsh's walkable route is now obvious: the thin, easily-missed marsh threads are replaced by a wide 3-tile plank BOARDWALK that runs continuously from where you start, around the central lagoon (north dry road or south road over the ford), straight through the central crossing and onto the Vault gate — so 'where can I walk?' reads at a glance against the bog. (Both causeways still loop and rejoin — it's a real marsh to explore, just legible now.)" },
  { v: "v0.75", t: "Two overworld HUD fixes. On phones the top bar no longer overlaps itself — the zone name, the party row, and the ♪/🗺/Aether controls now stack cleanly instead of piling on top of each other. And the location label is honest again: it could get stuck showing the wrong region (e.g. 'The Duskmarsh · Lv 7+' while you were actually back in Greenvale) if your map position and the tracked zone drifted apart; the zone now stays locked to wherever you're actually standing, so the region name, level, and the area you're in always agree." },
  { v: "v0.74", t: "Leaving a town drops you back where you entered — even after a reload. Before, if you saved inside a town and then Continued, the game forgot your spot on the world map, so walking back out dumped you at a zone's entrance (e.g. out by the first village) instead of the doorstep you came in from. Your overworld position is now remembered through a town visit and a save/Continue, so stepping out returns you exactly where you were." },
  { v: "v0.73", t: "Two movement fixes. Towns no longer pull you in by accident: stepping onto a town's overworld marker now ASKS first ('Enter Miregard? / Stay on the road') — so roaming the seamless world can't yank you off the map into a settlement (the minimap and World Map are view-only; they never moved you). And Miregard's entrance was fixed — you used to arrive jammed on a dead-end plank with black bog on two sides (so you 'couldn't walk all four directions'); you now arrive on an open boardwalk junction and can move freely. A guard test now keeps every town's arrival tile walkable." },
  { v: "v0.72", t: "The Bandit Warren, deepened — and a loot fix. The dungeon's three floors were reworked from corridors into real cross-linked warrens: the Tunnels (a ring of dens), the Barracks & a gated Flooded Vault wing (the Bloodknife lieutenant still guards the only way down — and the vault behind him), and the Kingpin's Throne Hall, each floor distinct with reward dead-ends off the safe path. You can now SEE the finale: the boss tile shows a 👑 throne + 'BOSS' marker (it used to render as a plain doorway — that's why it was easy to miss), and the galleries funnel you straight to the arena. Treasure now reads as treasure — every dungeon chest shows a 💰 'loot' glint so you can't walk past it. And a save fix: chests you've already looted STAY looted when you Continue a run (they were re-spawning before). (Throne/chest/stairs art is still placeholder.)" },
  { v: "v0.71", t: "Two combat read-outs. The top of the battle screen now shows the ELEMENTAL CHAIN — the five powers in their prey-order (SOL ▸ NOX ▸ ANIMA ▸ QUANTA ▸ UMBRAXIS ▸…), each beating the next, with the attunements actually in THIS fight lit up and the rest dimmed, so you can read your matchups at a glance. And every hero now has three GEAR SCORES — Offense, Defense, and an Overall — shown in the Party ▸ Equipment screen; when you go to equip a piece of loot, you see exactly how it moves them (e.g. 'Overall 159→172↑', green for better / red for worse) in both the bag and the swap screens, so 'is this an upgrade?' is answered at a glance." },
  { v: "v0.70", t: "The world comes alive — and goes deep. Every zone is now real country, not a flat field with a fight on it: rivers wind through and you cross them at bridges and fords (the water genuinely shapes the way), cliffs and ridgelines wall and funnel the route, with forests, snowfields, marsh-channels, harbor inlets and ruined moats giving each place its own character. And the world is inhabited — off the main paths you'll find roadside SHRINES that heal you, ENCAMPMENTS you can raid for loot (an optional fight), and landmarks/signposts (standing stones, a ruined windmill, a lighthouse, a wrecked hull, a crossroads sign). The Bandit Warren is now a real MULTI-FLOOR dungeon: beat the Brigadier at the mouth and DESCEND — B1's forking entry with a dead-end cache, B2 held by the bandit lieutenant Bloodknife who guards the only way down (and the vault behind him — no sneaking past), and B3, the Kingpin's hall. Stairs down and back up, dead-ends that reward the brave, and your floor is saved if you stop mid-crawl — the engine behind it powers every dungeon to come. Plus a '🗺 Map' button (or press M) for a 'you are here' minimap of the zone. (Terrain, POI and dungeon-stairs art is still placeholder; some names are draft.)" },
  { v: "v0.69", t: "A proper Party menu. The Party button now opens a classic FF-style hub: a roster down the left (portrait, name, level, class, attunement, MNA, HP, MP) and a column of sub-menus on the right — Items, Abilities, Equipment, Mana, Formation — with your current location and Aether pinned bottom-right. Abilities shows every hero's full skill tree (unlocked vs locked by MNA) and lets you cast a heal out of battle to mend the party. Equipment gives a detailed per-hero look at every piece (stats + affixes) beside a running total of that hero's HP/MP/ATK/MAG/SPD/+MNA. Mana is the point allocator; Formation lets you set each hero Front or Back and switch between a 3×2 and 2×3 line. Also: our currency is now Aether (◈) everywhere — gold is gone. And standard enemies got another big HP cut, so trash fights are quick now (bosses untouched)." },
  { v: "v0.68", t: "Battle screen + combat-feel pass. The lower window is now three equal panels: your commands (left), the party's HP/MP bars (centre), and a live, scrollable battle log (right) — which now also calls out buffs/debuffs applied and anything resisted. Standard enemies hit the field with ~35% less HP (bosses & rare monsters unchanged), so trash fights go quicker. Enemy HP bars are much shorter and the foes stand a bit closer to your heroes. Fallen heroes now STAY fallen until revived in town — no more accidental post-battle resurrections. Allocating MNA points no longer jumps you to the top of the Party window, so you can spend several in a row. And a new EGRESS button (up by your gold) instantly whisks the party back to town from the field." },
  { v: "v0.67", t: "A big quality-of-life pass. Every town & city is now re-enterable from the overworld (a 🏘️ marker by each region's entrance, not just Hearthford). Resting at an inn now costs a small fee. Tap an equipped item in the Party screen to see its full stats. Tap the battle log to expand a scrollable history — and every hit now reads out who took damage and how much, for heroes and enemies alike. Combat polish: crit bursts are centred on the enemy and sized to it, damage numbers pop above the enemy sprite (not the HP bar), and the kobold faces the right way. Random encounters are rarer (roughly every 10–15 steps instead of ~5). New higher-res forest & desert battle backdrops. And victory weapon drops now favor your party: 75% of dropped weapons match a class you're already running (farm upgrades for your comp) — while treasure chests still roll evenly across all classes for variety." },
  { v: "v0.66", t: "You can go home again. Hearthford is now re-enterable — a village marker sits just inside the Greenvale entrance, and stepping onto it walks you back into town (Inn, Market, Smith, Shrine, and the Vault) any time. Leaving town drops you right back where you were on the map. Handy for stashing loot mid-run." },
  { v: "v0.65", t: "The first continent is whole. Aurelion's last six regions are built and open to roam — the whole landmass is now one seamless world, from the Greenvale shire all the way to the southern sea. A main path runs through the FROSTPEAK HIGHLANDS (Lv 16–20) — frozen passes and a silent dwarven stronghold, gated by the Hold-Warden and guarded at its heart by the Glacier Guardian — and ends at SUNBRIDGE (Lv 21–25), the great besieged port and the new climax of the run: fight through the quays to the citadel and the Risen Leviathan, the hardest fight in the game. Off that path lie four optional regions to explore for loot and a fight: the STORM COAST (wreckers and sea-beasts on a wave-lashed shore), the RIVERHEARTH outskirts (road-bandits and smugglers around the trade capital), DAWNFALL HOLD (a breached frontier fort overrun by the wilds), and the WHISPER HILLS (a haunted monastery and its crypt). Each new region looks and sounds like itself now — snowfields, harbor, ruins, sacred hills — with its own music; and because it's one big map with no level gates, the world warns you when you wander somewhere far above your level. (Region art and many names are still first-draft placeholders.)" },
  { v: "v0.64", t: "A new region to ride into — Goldmeadow Plains, 'the Breadbasket' of Aurelion. After the close, grim Duskmarsh the world opens up wide: rolling golden wheat, farm tracks and drystone walls, a creek crossing — and nowhere to hide. The grim tide has spilled north onto the plains, so the once-peaceful breadbasket is a running battle across open ground. Roam there seamlessly from the rest of the continent (it's the next step past the marsh, Lv 11–15): three looping farm tracks that rejoin at a crossroads, treasure down the branches, and a gilded beast gorging in the wheat for the lucky. A new war-host to fight — raiders, marauders, harriers, wild dogs, carrion birds and armored reavers — gated by a Raider War-Captain at the occupied windmill, whose Undercroft you descend into to face the Reaping Warlord (who enrages when cornered). New bittersweet, martial plains music, a tense granary dungeon theme, and the biggest boss theme yet. (Plains/windmill/new-enemy art is still placeholder; some names are first-draft.)" },
  { v: "v0.63", t: "Battle + boss pass: heroes now all render the same size and enemies line up vertically with them; bosses are drawn markedly larger. New boss ENRAGE phase — at 20% HP a flagged boss crossfades from its 'alpha' to a fearsome 'omega' form and, for the rest of the fight, moves twice as fast and hits twice as hard (the Greenvale Kingpin and Cave Troll both enrage). Party-building rule: max 2 heroes of any one Attunement, so you can't hard-stack a single power. And a persistent Vault in town — stash loot safely; it's kept between runs." },
  { v: "v0.62", t: "The world is seamless now. No more loading between zones — you roam all of Aurelion as one continuous map: walk out of Greenvale, across the open continent, and into Silverwood (and the Duskmarsh) with the land, foes, and music shifting under you as you go. Dungeons are still entered through their mouths, and your run saves your spot in the world. The land between the built regions is open to wander (more to fill in there over time). (The classic per-zone mode is still there as a fallback.)" },
  { v: "v0.61", t: "Greenvale feels like five places, not one. The shire is rebuilt around its Areas: the ground and the foes you meet shift as you roam — open Hearthford Commons (gentle slimes/kobolds), the orderly Orchard Ridge, the wind-rippled Bandit Fields (bandits & mages), the hushed Hidden Grove where Hogger lurks, and the Warren Approach run-up to the dungeon mouth. Same smooth difficulty, just a world with a real sense of place. (First zone rebuilt to the new framework; the others follow.)" },
  { v: "v0.60", t: "Zones now have real sub-regions. Drill into Greenvale (or Silverwood / the Duskmarsh) on the World Map and you'll see it divided into organic Areas that tile the whole zone — Greenvale's Hearthford Commons, Orchard Ridge, Bandit Fields, the Hidden Grove, and the Warren Approach (where the dungeon mouth sits) — each with its own terrain/encounter character. Groundwork for rebuilding the zones so every step of the map knows where you are and what belongs there." },
  { v: "v0.59", t: "The Underworld is on the map. Toggle to the Underworld on the World Map and you'll now see the buried machine-city — all 13 canon complexes (the Worldroot at its heart, Titan Core Prime, the Celestial Archive, the Forge Cities, the Transit Nexus, the Access Shafts, and more) placed to scale as one realm, 'The Forgotten Civilization', with the access points aligned under their surface continents. The deep is backlog for now, but the whole world — surface and under — is laid out to fit." },
  { v: "v0.58", t: "Explore the World Map by clicking in. Click a continent to zoom into it, a zone to zoom into its areas, an area to focus it — with a breadcrumb (Overworld › Aurelion › Greenvale › …) and a Back button to step out. The map is now a drill-down browser of the whole hierarchy; built zones are highlighted and the backlog is visible at every level." },
  { v: "v0.57", t: "The whole world, to scale. The World Map now shows all four continents — Aurelion, Varkhaz, Myr'Thalas, and the Sundering — around the Great Expanse, with all 25 regions (incl. the five Sundering scars) placed in their canon-map positions as organic shapes. The world was right-sized to the real map's proportions (960×640, no longer a square) so everything fits at one consistent scale before we fill it in. The three built zones stay highlighted; the rest is the backlog to come." },
  { v: "v0.56", t: "The World Map looks like a real place now. Aurelion is drawn from the actual world map — an irregular coastline with organic, non-rectangular regions in their true positions: Greenvale and Silverwood (and the Duskmarsh) highlighted as built, and the rest of the continent (Goldmeadow, Storm Coast, Riverhearth, Frostpeak, Dawnfall, Whisper Hills, Sunbridge) sketched in as the backlog to come. Under the hood the map model moved from boxes to polygons, so every future region can have natural borders." },
  { v: "v0.55", t: "A World Map you can watch grow. New 'World Map' screen on the title lays out the whole world as one 250×250 space with Aurelion and its zones (Greenvale, Silverwood, the Duskmarsh) painted in and the rest as open backlog — the framework we'll build the world against (Map › Continent › Zone › Area). Under the hood: the groundwork for a seamless, no-load world — dungeons are now entered through a mouth (step onto the cave/vault entrance to descend) so the overworld can later stitch into one continuous map. (Area names are first-draft, to be named.)" },
  { v: "v0.54", t: "Zones are open now, not corridors. Greenvale, Silverwood, and the Duskmarsh were rebuilt as interconnected networks — multiple routes to the boss, big loops that rejoin so exploring is a circuit instead of an out-and-back, and treasure (and the rare-monster lairs) sitting along alternate paths you choose between, not dead-end spurs off a straight road. The dungeons loop too: the forks rejoin before the boss arena. Same gates and guaranteed-no-soft-lock, just a real world to roam." },
  { v: "v0.53", t: "Save & resume — your run now saves automatically (after fights, on entering/leaving towns, on gear changes) and a Continue button appears on the title screen to pick up where you left off. Built to survive new versions: because we keep adding to the world, a save made before an update still loads after it — your party, levels, gear and gold carry over, and only things that genuinely can't (like a spot in a zone that changed) gracefully reset. So you can keep playing while we keep building." },
  { v: "v0.52", t: "Fights bite now. A telemetry-driven combat pass: your damage was never the problem (it's on-target) — the run had just gone trivial, so enemies hit harder from the first fight, you level a little slower (less over-leveling), and the long 'sponge' champion/elite fights are much shorter. Bosses still climb Greenvale → Silverwood → the Cave Troll (the hardest), now without one-shots or slogs." },
  { v: "v0.51", t: "Fix: your character was invisible after arriving in a town straight from a boss fight (most visibly Riverhearth) — only the gold 'you are here' ring showed, not your hero. Town entry now re-syncs the view the way every other screen does, so your character always renders. (Also hardened so the walker can never clip off the top edge.)" },
  { v: "v0.50", t: "A whole new region — Silverwood, the Ancient Forest — now sits between Greenvale and the Duskmarsh, so the journey runs Hearthford ▸ Greenvale ▸ Riverhearth ▸ Silverwood ▸ Miregard ▸ the Duskmarsh. It's a hushed, enclosing old-growth wood: a winding root-trail through linked hollows, branches that hide treasure, the Mossback Tortoise's lair off the dark path, and a new dungeon — the Sunless Grove — that gates the way to its boss, the Hollow King. New forest foes (Direwolf, Thornling, Sylvan Archer, Gloom Wisp, Barkhide Brute, Spriggan, Elder Treant), its own hushed forest theme, and a re-smoothed three-zone difficulty curve that climbs into a Cave Troll finale that genuinely bites. (Forest + new-enemy art still placeholder.)" },
  { v: "v0.49", t: "Riverhearth — Gaia's first true city. After Greenvale falls you now arrive in a sprawling river trade capital you actually walk through: four districts (the docks, the market square, the civic keep, and the residential quarter), grand avenues, and a river crossed by two bridges. Ten townsfolk to talk to — a bellowing crier, dockhands, a merchant guildmaster, the guard captain, a ferryman, a haughty noble, a busker, kids by the fountain — and its own grand, bustling theme. The journey now runs home village → wilds → great city → grim outpost → marsh: Hearthford ▸ Greenvale ▸ Riverhearth ▸ Miregard ▸ the Duskmarsh. (City art still placeholder.)" },
  { v: "v0.48", t: "The Duskmarsh, rebuilt to match. The second zone is now a real grim mire to pick through — a narrow causeway east pinched by black water, with detours that pay off (a fog-bound bog pocket and a sunken ruin hiding treasure and a Metal Babble lair). The Drowned Vault is a proper flooded dungeon now: a dead-end side cell vs. the long gallery route down to the Cave Troll's arena. And there's a new place to walk: Miregard, a half-drowned marsh outpost on stilts that serves as the hub before the marsh, with its own grim townsfolk to talk to and its own fog-bound music. Both POC zones are now rebuilt from the ground up. (Mire/outpost art still placeholder.)" },
  { v: "v0.47", t: "Greenvale, rebuilt from the ground up. The old straight corridor is gone — Greenvale is now a real shire to roam: a winding road east with branches that pay off (orchard, meadow, and thicket each hide treasure) and Hogger's lair tucked away in a hidden southern grove. The Bandit Warren is a proper dungeon now — forking tunnels, a dead-end store room with the richest hoard, and a guarded route to the Kingpin's arena. Hearthford's townsfolk have real personalities to talk to, the village has its own warm theme, and the difficulty curve was smoothed so deep fights pressure you without cheap one-shot wipes. (Town/NPC art still placeholder.)" },
  { v: "v0.46", t: "Crisp new hero art — all 45 class figures re-cut from Dara's chroma-key (magenta-background) composite via a colour-key knockout, so even the near-black NOX/UMBRAXIS robes come through solid and true to the source (the old dark-flood knockout couldn't separate black-on-black). The figures already show their weapon, so the separate weapon-overlay layer is disabled for now — we'll revisit overlaying loot weapons later." },
  { v: "v0.45", t: "Hearthford — your adventure now begins INSIDE a real, lived-in starting village, not a menu. Roam the green, rest at the inn, visit the market/smith/shrine, and walk up to the townsfolk — Elder Maelis, Watchman Bram, Little Pip, Goodwife Tansy, Innkeeper Doral — to talk to them, then take the north gate out into Greenvale. First step of a ground-up world rebuild: towns and cities you actually live in. (Art is placeholder for now.)" },
  { v: "v0.44", t: "Crash-proof telemetry — your in-progress run is now mirrored as you play, so a crash or closed tab no longer loses it: the next time you open the game it quietly recovers that run and sends it to the repo. Finished runs still auto-save as before." },
  { v: "v0.43", t: "Battle-screen layout pass — bigger battlefield, slimmer command/roster bar (70/30 split); hero bars sit flush at the bottom edge; heroes clustered closer together; names removed from the field sprites and the roster reordered (Auren · Sephi · Kaela · Liora · Rion); fresh Greenvale plains backdrop." },
  { v: "v0.42", t: "The Greenvale Outpost is now a real, walkable town — you roam a cobbled plaza and step up to each building to use it: the Inn (free rest), the Merchant (Supplies), the Smith, and the Revive shrine, then the south gate to head on. Replaces the menu-style hub." },
  { v: "v0.41", t: "First town — the Greenvale Outpost hub now sits between zones (in place of the bare merchant): Rest & Recover (free full heal), Visit Merchant, Revive Fallen, Character Status, Head Back Out, Start Over — plus a Smith placeholder for crafting to come." },
  { v: "v0.40", t: "UX pass from Dara's notes — Party screen redone with a vertical, thumb-friendly MNA allocator (big +/− per Attunement, free undo); boss sprites render big and centered in battle; the combat log is now a calm 2-line ticker instead of a cluttered scroll over the party." },
  { v: "v0.39", t: "The Data screen is now an editor — toggle Edit to tweak enemy and ability numbers live (validated as you go), with the changes persisting and an Export to a JSON patch. Lets a designer balance by hand; the code stays the source of truth." },
  { v: "v0.38", t: "Content browser — a 'Data' screen on the title that lays out the whole game database (bestiary, abilities, the 45 classes, zones) for design/balance visibility at a glance." },
  { v: "v0.37", t: "Difficulty + pacing retune — fights now actually cost HP and bosses bite, tuned against a 'skilled' player model in the sim; steeper XP so you reach the boss around level 10 instead of out-leveling it." },
  { v: "v0.36", t: "High-res hero backgrounds — a proper Greenvale grassland plus distinct backdrops for the Bandit Warren (warm) and Drowned Vault (cold), each dungeon now its own scene." },
  { v: "v0.35", t: "Affinity ring ratified + tuned to a modest ±15% (was ±50%) so gear and skill matter more than matchup; enemies rebalanced to suit." },
  { v: "v0.34", t: "Battle visual pass — crisp sprite outlines + contrast, formations grounded out of the sky, higher-fidelity re-sliced backgrounds, hero names colored by Attunement; Warmech ultra-rare added." },
  { v: "v0.33", t: "Cave Troll boss re-tuned to NOX so the final fight has a real affinity matchup." },
  { v: "v0.32", t: "Dara's canon bestiary (Greenvale + Drowned Vault, SOL/NOX bosses); SOL de-weighted everywhere; ultra-rare monster tier — Hogger, Metal Slime, Metal Babble." },
  { v: "v0.31", t: "Crit-hit burst VFX — a per-Attunement spark that pops and fades on a critical." },
  { v: "v0.30", t: "Six gear slots (helmet/armor/gloves/boots/weapon/trinket); level-banded loot with ilvl scaling; sell loot back to the merchant." },
  { v: "v0.29", t: "All 45 classes get distinct ability kits generated from REQUIEM canon; mid-run telemetry save." },
  { v: "v0.28", t: "Serverless telemetry auto-save — runs commit themselves to the repo via a Cloudflare Worker." },
  { v: "v0.27", t: "Loot → equip flow with green/red stat-delta arrows." },
  { v: "v0.26", t: "Dungeon tilesets + combat feel pass — faster enemies, stun immunity for tough foes, front/back formation." },
  { v: "v0.25", t: "Loot repass so every Attunement drops; telemetry copy-export; field art polish." },
  { v: "v0.24", t: "Party of five (3 front / 2 back), champion packs, Greenvale tileset, build-any-Attunement Roster picker." },
  { v: "v0.23", t: "Painterly art pass — per-Attunement weapons, 45 class bodies, armor icons, hero-sized weapons." },
  { v: "v0.22", t: "All 45 class bodies + per-Attunement Dual Swords and armor icons." },
  { v: "v0.21", t: "Painterly per-Attunement weapon art + weaponless SOL hero bodies." },
  { v: "v0.20", t: "Fixed accidental battle-exit from stray taps at the start of a fight." },
  { v: "v0.19", t: "Wired Dara's painterly terrain backgrounds into battle." },
  { v: "v0.18", t: "Applied the UX-review findings — legibility and clarity polish." },
  { v: "v0.17", t: "Skill-tree visualizer + ability tooltips; foreign-weapon fixes." },
  { v: "v0.16", t: "Beyond SOL — weapon-driven reclassing and the first NOX classes." },
  { v: "v0.15", t: "Dungeons; ingested the base-model and gear art." },
  { v: "v0.14", t: "MNA allocator UI + respec." },
  { v: "v0.13", t: "MNA progression engine + loot scaling, more skills, rebalance." },
  { v: "v0.12", t: "Re-architected to modular TypeScript + Vite (the frozen single-file build is v0.11)." },
  { v: "v0.11", t: "Second zone — The Duskmarsh — and a merchant between zones." },
  { v: "v0.10", t: "Per-screen music style; battle stray-tap fix." },
  { v: "v0.9", t: "Punchier home theme + three switchable music variants." },
  { v: "v0.8", t: "Procedural chiptune soundtrack (Web Audio — no asset files)." },
  { v: "v0.7", t: "Paper-doll character compositor (ADR 0004)." },
  { v: "v0.6", t: "Transparent sprites + dark scenes; equipped weapon shown on heroes." },
  { v: "v0.5", t: "Real difficulty via depth-scaled enemies; glitch and art-bleed fixes." },
  { v: "v0.4", t: "Wired in Dara's real art — weapons, enemies, heroes." },
  { v: "v0.3", t: "Bigger bestiary, enemy abilities, a mini-boss gate, and treasure chests." },
  { v: "v0.2", t: "Longer run, gradual leveling, tougher fights; fixed a victory soft-lock." },
  { v: "v0.1", t: "First playable Greenvale vertical slice." },
];
